from dataclasses import dataclass

@dataclass
class Score:
    value: float
    def __post_init__(self):
        if not 0.0 <= self.value <= 1.0:
            raise ValueError("score fuera de [0,1]")

print(Score(0.5))
try:
    Score(1.5)
except ValueError as e:
    print("invalid", e)

from dataclasses import dataclass

@dataclass
class Email:
    raw: str
    def __post_init__(self):
        if "@" not in self.raw:
            raise ValueError("email inválido")
        self.raw = self.raw.strip().casefold()

print(Email("  A@B.COM "))

