from dataclasses import dataclass

@dataclass
class Contact:
    email: str
    @property
    def masked_email(self):
        local, _, dom = self.email.partition("@")
        return (local[:1] + "***@" + dom) if local else "***@" + dom

print(Contact("ana@ejemplo.pe").masked_email)

