from typing import Protocol

class EntityStore(Protocol):
    def get(self, entity_id: str): ...
    def save(self, entity) -> None: ...

class FakeStore:
    def __init__(self):
        self._d = {}
    def get(self, entity_id: str):
        return self._d.get(entity_id)
    def save(self, entity) -> None:
        self._d[entity["id"]] = entity

store: EntityStore = FakeStore()
store.save({"id": "E1"})
print(store.get("E1"))

class InMemoryStore:
    def __init__(self):
        self.data = {}
    def get(self, eid):
        return self.data.get(eid)
    def save(self, ent):
        self.data[ent["id"]] = ent
        return "saved"

s = InMemoryStore()
print(s.save({"id": "E2", "name": "Ada"}))
print(s.get("E2"))

class Repo:
    def __init__(self):
        self._db = {}
    def get(self, eid):
        return self._db.get(eid)
    def save(self, ent):
        self._db[ent["id"]] = ent

r = Repo()
r.save({"id": "E1", "score": 0.2})
print(r.get("E1"))

def to_dict(entity):
    return {"entity_id": entity["entity_id"], "name": entity["name"]}

def from_dict(d):
    return {"entity_id": d["entity_id"], "name": d["name"]}

raw = {"entity_id": "E1", "name": "Ana"}
print(to_dict(from_dict(raw)))

class FakeStore:
    def __init__(self):
        self.saved = []
    def save(self, e):
        self.saved.append(e)

def service_register(store, ent):
    if "id" not in ent:
        raise ValueError("id required")
    store.save(ent)
    return "ok"

fs = FakeStore()
print(service_register(fs, {"id": "E1"}))
print(len(fs.saved))
